-- 검증
SELECT COUNT(*) AS total_menus FROM "Menu";
SELECT r.name, r.zone, COUNT(m.id) AS menu_count FROM "Restaurant" r LEFT JOIN "Menu" m ON m."restaurantId" = r.id GROUP BY r.id, r.name, r.zone HAVING COUNT(m.id) = 0 ORDER BY r.zone, r.name;

